func countWorkerStates(workers []*cluster.Worker) (active, draining, dead int) {
	for _, w := range workers {
		switch w.State {
		case cluster.WorkerActive:
			active++
		case cluster.WorkerDraining:
			draining++
		case cluster.WorkerDead:
			dead++
		}
	}
	return
}

